def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python expression that returns a dictionary.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression is invalid, contains disallowed elements, or does not evaluate to a dictionary.
    """
    try:
        # Parse the expression into an AST
        tree = ast.parse(transform_map_expr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}") from e

    validator = ExpressionValidator()
    try:
        validator.visit(tree)
    except SyntaxError as e:
        raise ValueError(f"Disallowed element in expression: {e}") from e

    # Compile the AST to bytecode
    try:
        code = compile(tree, '<string>', 'eval')
    except Exception as e:
        raise ValueError(f"Could not compile expression: {e}") from e

    # Set up a safe execution environment
    safe_globals = {
        '__builtins__': None,  # No built-in functions or constants
        'input_data': input_data,
        'True': True,
        'False': False,
        'None': None,
        'len': len,
        'str': str,
        'int': int,
        'float': float,
        'bool': bool,
        'abs': abs,
        'round': round,
        'max': max,
        'min': min,
        'sum': sum,
    }

    try:
        result = eval(code, safe_globals)
    except Exception as e:
        raise ValueError(f"Error evaluating expression: {e}") from e

    if not isinstance(result, dict):
        raise ValueError("Expression must evaluate to a dictionary")

    return result

